import React, { useState, useRef } from "react";
import { Link } from "react-router-dom";

export default function Login() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [emailError, setEmailError] = useState(false);
  const [passwordError, setPasswordError] = useState(false);
  const [buttonPosition, setButtonPosition] = useState({ x: 0, y: 0 });
  const [buttonText, setButtonText] = useState("Sign In");
  const [userType, setUserType] = useState("employee"); // 'manager' or 'employee'
  const buttonRef = useRef(null);
  const containerRef = useRef(null);
  const [isMoving, setIsMoving] = useState(false);

  const validateForm = () => {
    let isValid = true;

    if (!email || !email.includes("@") || !email.includes(".")) {
      setEmailError(true);
      isValid = false;
    } else {
      setEmailError(false);
    }

    if (!password || password.length < 6) {
      setPasswordError(true);
      isValid = false;
    } else {
      setPasswordError(false);
    }

    return isValid;
  };

  const moveButton = () => {
    if (buttonRef.current && containerRef.current && !isMoving) {
      setIsMoving(true);
      const button = buttonRef.current;
      const container = containerRef.current;
      const buttonRect = button.getBoundingClientRect();
      const containerRect = container.getBoundingClientRect();

      const maxX = Math.max(0, containerRect.width - buttonRect.width);
      const maxY = Math.max(0, containerRect.height - buttonRect.height);

      const newX = Math.random() * maxX;
      const newY = Math.random() * maxY;

      setButtonPosition({ x: newX, y: newY });

      setTimeout(() => {
        setIsMoving(false);
      }, 300);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateForm()) {
      setButtonText("Signing In...");
      setTimeout(() => {
        alert(`Welcome ${userType === "manager" ? "Manager" : "Employee"}! Form submitted successfully!`);
        setButtonText("Sign In");
        setButtonPosition({ x: 0, y: 0 });
      }, 1000);
    } else {
      moveButton();
      setButtonText("❌ Complete!");
      setTimeout(() => {
        setButtonText("Sign In");
      }, 1500);
    }
  };

  const handleEmailChange = (e) => {
    setEmail(e.target.value);
    if (emailError) setEmailError(false);
  };

  const handlePasswordChange = (e) => {
    setPassword(e.target.value);
    if (passwordError) setPasswordError(false);
  };

  return (
    <div 
      className="relative w-full min-h-screen"
      style={{
        background: "linear-gradient(135deg, #14532d 0%, #000000 50%, #14532d 100%)",
        position: "fixed",
        top: 0,
        left: 0,
        right: 0,
        bottom: 0,
        overflowY: "auto",
      }}
    >
      <div className="container mx-auto px-4 h-full">
        <div className="flex content-center items-center justify-center h-full min-h-screen">
          <div className="w-full lg:w-5/12 px-4">
            {/* Form Container - Transparent with rounded corners */}
            <div 
              className="relative flex flex-col min-w-0 break-words w-full mb-6 shadow-2xl border-0 overflow-hidden"
              style={{
                background: "rgba(0, 0, 0, 0.5)",
                backdropFilter: "blur(12px)",
                borderRadius: "24px",
                border: "1px solid rgba(74, 222, 128, 0.3)",
              }}
            >
              <div className="flex-auto px-4 lg:px-10 py-10">
                <form onSubmit={handleSubmit}>
                  <div className="relative w-full mb-4">
                    <label className="block uppercase text-white text-xs font-bold mb-2">
                      Email
                    </label>
                    <input
                      type="email"
                      value={email}
                      onChange={handleEmailChange}
                      className={`
                        px-3 py-3 placeholder-white/40 text-white 
                        rounded-2xl text-sm shadow focus:outline-none 
                        focus:ring-2 focus:ring-green-500 w-full 
                        transition-all duration-150
                        ${emailError 
                          ? "bg-red-500/20 border-2 border-red-500/50" 
                          : "bg-white/10 border border-white/20"}
                      `}
                      style={{ backdropFilter: "blur(8px)" }}
                      placeholder="your@email.com"
                    />
                    {emailError && (
                      <p className="text-red-400 text-xs mt-1 animate-pulse">
                        ⚠️ Please enter a valid email address
                      </p>
                    )}
                  </div>

                  <div className="relative w-full mb-4">
                    <label className="block uppercase text-white text-xs font-bold mb-2">
                      Password
                    </label>
                    <input
                      type="password"
                      value={password}
                      onChange={handlePasswordChange}
                      className={`
                        px-3 py-3 placeholder-white/40 text-white 
                        rounded-2xl text-sm shadow focus:outline-none 
                        focus:ring-2 focus:ring-green-500 w-full 
                        transition-all duration-150
                        ${passwordError 
                          ? "bg-red-500/20 border-2 border-red-500/50" 
                          : "bg-white/10 border border-white/20"}
                      `}
                      style={{ backdropFilter: "blur(8px)" }}
                      placeholder="••••••••"
                    />
                    {passwordError && (
                      <p className="text-red-400 text-xs mt-1 animate-pulse">
                        ⚠️ Password must be at least 6 characters
                      </p>
                    )}
                  </div>

                  {/* User Type Selection with Icons */}
                  <div className="mb-6">
                    <label className="block text-white text-sm font-semibold mb-3">
                      Login as:
                    </label>
                    <div className="flex gap-4">
                      {/* Manager Button */}
                      <button
                        type="button"
                        onClick={() => setUserType("manager")}
                        className={`
                          flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl 
                          transition-all duration-300 font-semibold
                          ${userType === "manager" 
                            ? "bg-green-600 text-white shadow-lg scale-105" 
                            : "bg-white/10 text-white/70 hover:bg-white/20 border border-white/20"}
                        `}
                      >
                        <i className="fas fa-user-tie text-lg"></i>
                        <span>Manager</span>
                      </button>

                      {/* Employee Button */}
                      <button
                        type="button"
                        onClick={() => setUserType("employee")}
                        className={`
                          flex-1 flex items-center justify-center gap-2 px-4 py-3 rounded-xl 
                          transition-all duration-300 font-semibold
                          ${userType === "employee" 
                            ? "bg-green-600 text-white shadow-lg scale-105" 
                            : "bg-white/10 text-white/70 hover:bg-white/20 border border-white/20"}
                        `}
                      >
                        <i className="fas fa-user-circle text-lg"></i>
                        <span>Employee</span>
                      </button>
                    </div>
                  </div>

                  <div>
                    <label className="inline-flex items-center cursor-pointer">
                      <input
                        id="customCheckLogin"
                        type="checkbox"
                        className="form-checkbox rounded text-green-500 ml-1 w-5 h-5 bg-white/20 border-white/30"
                      />
                      <span className="ml-2 text-sm font-semibold text-white">
                        Remember me
                      </span>
                    </label>
                  </div>

                  {/* Button Container with moving button effect */}
                  <div 
                    ref={containerRef}
                    className="relative text-center mt-6 min-h-[60px]"
                  >
                    <button
                      ref={buttonRef}
                      type="submit"
                      className="bg-green-700 hover:bg-green-600 text-white font-bold uppercase px-6 py-3 rounded-2xl shadow-xl hover:shadow-2xl outline-none focus:outline-none w-full ease-linear transition-all duration-300 relative"
                      style={{
                        transform: `translate(${buttonPosition.x}px, ${buttonPosition.y}px)`,
                        transition: "transform 0.3s ease-in-out",
                      }}
                    >
                      {buttonText}
                    </button>
                  </div>
                </form>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
